require "util.LotteryUtil"

TaskConfig = {}
TaskConfig.TaskList = {}

TaskConfig.MainTaskList = {}
TaskConfig.DareTaskList = {}

TaskConfig.PossibleList = {}
TaskConfig.TASK_LEVEL_COUNT = 5
TaskConfig.RANDOM_REWAARD_ID = 3000

function TaskConfig:initConfig(task_list)
    LotteryUtil:setRandomSeed()
    local possible_list = {}
    for _, task in pairs(task_list) do
        local item = {
            Id = tonumber(task.Id),
            TaskSort = tonumber(task.TaskSort),
            Quality = tonumber(task.Quality) or 1,
            Level = tonumber(task.Level) or 0,
            Title = task.Title or "",
            Icon = task.Icon or "",
            --askPoolId = tonumber(task.GroupId),
            NextTaskId = tonumber(task.NextTaskId) or 0,
            TaskTypeId = tonumber(task.TaskTypeId) or 0,
            GoalNum = tonumber(task.GoalNum) or 0,
            Remarks = tonumber(task.Remarks) or 0,
            GameType = StringUtil.split(task.GameType, "#"),
            --ActiveValue = tonumber(task.ActiveValue),
            Weight = tonumber(task.Weight),
            SortValue = tonumber(task.SortValue) or 0,
            RewardIds = StringUtil.split(task.RewardIds, "#"),
            RewardWeigth = StringUtil.split(task.RewardWeigth, "#"),
            RemarksMeta = tonumber(task.RemarksMeta) or -1,
            Stage = StringUtil.split(task.Stage, "#"),
            StageId = tonumber(task.StageId) or 0
            
        }

        self.TaskList[item.Id] = item
        if item.TaskSort == Define.TaskMain.Dare then
            --TaskPoolManager:putTaskIntoPool(item)
            local cur_StageId = item.StageId
            if possible_list[cur_StageId] == nil then
                possible_list[cur_StageId] = {} 
                possible_list[cur_StageId].quality_list = {}
                possible_list[cur_StageId].stageId = item.StageId
            end


            if possible_list[cur_StageId].quality_list[item.Quality] == nil then
                possible_list[cur_StageId].quality_list[item.Quality] = {} 
                possible_list[cur_StageId].quality_list[item.Quality].list = {}
                possible_list[cur_StageId].quality_list[item.Quality].sum_weight = 0
            end

            if self.DareTaskList[cur_StageId] == nil then
                self.DareTaskList[cur_StageId] = {} 
            end

            if  self.DareTaskList[cur_StageId][item.Quality] == nil then
                self.DareTaskList[cur_StageId][item.Quality] = {}
            end

            possible_list[cur_StageId].quality_list[item.Quality].sum_weight = possible_list[cur_StageId].quality_list[item.Quality].sum_weight + item.Weight
            table.insert(self.DareTaskList[cur_StageId][item.Quality], item)
            table.insert(possible_list[cur_StageId].quality_list[item.Quality].list, item.Weight)

        elseif item.TaskSort == Define.TaskMain.Mainline then
            self.MainTaskList[item.Id] = item
        end
    end

    for sta_k, sta_v in pairs(possible_list) do 
        for qua_k, qua_v in pairs(sta_v.quality_list) do   
            for key, value in pairs(qua_v.list) do
                value = value / qua_v.sum_weight
            end 

            local group = (sta_v.stageId - 1) * 4 + qua_k
            LotteryUtil:initRandomSeed(group, qua_v.list)
        end
    end
end

function TaskConfig:initPossibleConfig(possible_list)
    LotteryUtil:setRandomSeed()
    for _, possible in pairs(possible_list) do
        local item = {
            Id = tonumber(possible.Id),
            Quality = tonumber(possible.Quality) or 1,
            Possible = StringUtil.split(possible.Possible, "#"),
        }
        self.PossibleList[item.Id] = item

        local data = {}
        local sum_weight = 0
        for k, v in ipairs(item.Possible) do
            sum_weight = sum_weight + tonumber(v)
            table.insert(data,tonumber(v))
        end

        for i, v in ipairs(data) do
            v = v / sum_weight
        end

        LotteryUtil:initRandomSeed(1000 + item.Quality, data)
    end
end

function TaskConfig:getDareTaskByQualityAndId(quality, Id, scoreLevel)
    print(" quality=="..quality.."  Id=="..Id.."  scoreLevel=="..scoreLevel)
    local data = self.DareTaskList[1][1][1]
    if self.DareTaskList[scoreLevel] == nil or self.DareTaskList[scoreLevel][quality] == nil then
        return data
    end


    for k, task in pairs(self.DareTaskList[scoreLevel][quality]) do
        if Id == k then
            return task
        end
    end
    return data
end

function TaskConfig:getTaskMainGroup(level)
    local data = {}
        for _, group in pairs(self.MainTaskList) do
            if group.TaskSort == Define.TaskMain.Mainline then
                if group.Level <= level then
                    table.insert(data, group)
                end
            end
        end
    return data
end

function TaskConfig:getTaskById(taskId)
    return self.TaskList[tonumber(taskId)]
end

function TaskConfig:getTaskIds(level)
    local data = {}
    for k, v in pairs(self.MainTaskList) do
        if level == v.Level then
            table.insert(data, v.Id)
        end
    end
    return data
end

function TaskConfig:include(curtable, value)
    for _, v in pairs(curtable) do
        if v == value then
            return true
        end
    end
    return false
end

function TaskConfig:ListInclude(curtable, data)
    for _, v in pairs(curtable) do
        if v.quality == data.quality and v.id == data.id then
            return true
        end
    end
    return false
end


function TaskConfig:getScoreLevel(level)
    local scoreLevel = 1
    for k, task in pairs(TaskConfig.TaskList) do
        if task.TaskSort == Define.TaskMain.Dare then
            if level >= tonumber(task.Stage[1]) and level <= tonumber(task.Stage[2]) then
                scoreLevel = task.StageId
                break
            end
        end
    end
    HostApi.log("scoreLevel =="..scoreLevel)
    return scoreLevel
end


return TaskConfig